INSERT INTO public.photos VALUES (21902, 'Ferial 1939', 'Imagen capturada desde cierta altura en el ferial de atracciones instalado durante las Fiestas del Pilar del a‚îú‚ñío 1939 (oficialmente denominado por el r‚îú¬Ægimen "A‚îú‚ñío de la Victoria") en el Campo de la Victoria, despejado entorno de la nueva plaza de San Francisco (antes de Espa‚îú‚ñía), donde la actual calle de Bruno Solano. Hacia el fondo, el arbolado paseo de Fernando el Cat‚îú‚îÇlico (antes avenida de Francisco Giner de los R‚îú¬°os), y las pioneras manzanas 49 y 50 de Casas Baratas del ensanche de Miralbueno, finalizadas a principios de la d‚îú¬Æcada con proyecto del arquitecto Secundino Zuazo Ugalde (delimitadas actualmente entre las calles de Cortes de Arag‚îú‚îÇn, Corona de Arag‚îú‚îÇn, Baltasar Graci‚îú√≠n y avenida de Goya). Al fondo y hacia la derecha, la torre de San Pablo y la c‚îú‚ïëpula de la iglesia de Santiago el Mayor se‚îú‚ñíalan la distancia de la ciudad consolidada.', 1939, 1939, 1939, 'Anos 30', 'UNIVERSIDAD', 41.63962100, -0.89517100, '0101000020E6100000D57B2AA73DA5ECBFDB6AD619DFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51470891212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51470891212.webp', 'https://www.flickr.com/photos/zaragozaantigua/51470891212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21936, 'Grupo Francisco Caballero 1946', 'AHPZ. Estudio Coyne. La manzana entre las calles Andr‚îú¬Æs Piquer, Santa Teresa, Luis Vives y Bruno Solano, configura el denominado "Grupo Francisco Caballero" de 113 viviendas protegidas, con proyecto de Jos‚îú¬Æ de Yarza Garc‚îú¬°a y Alejandro Allanegui P‚îú¬Ærez, finalizadas en 1946. Imagen tomada desde la calle Bruno Solano, en un entorno que se estaba edificando. Al fondo, la calle Luis Vives con las tapias de la Editorial Vives.', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63934000, -0.89474200, '0101000020E6100000B9718BF9B9A1ECBF2783A3E4D5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15194622218.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15194622218.webp', 'https://www.flickr.com/photos/zaragozaantigua/15194622218/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22033, 'Calle de Toledo 1941', 'Imagen capturada en el primer tramo de la calle de Toledo, comprendido entre las calles de Burgos y la de Salamanca, y centrada en los inmuebles en construcci‚îú‚îÇn de los n‚îú‚ïëmeros 4, 6 y 8. Esta despejada zona que se extend‚îú¬°a entre la estaci‚îú‚îÇn de Cari‚îú‚ñíena y la carretera de Valencia se convirti‚îú‚îÇ a finales de los a‚îú‚ñíos veinte en el emplazamiento del Circo Krone, de forma que cuando fue urbanizada tras la guerra civil de 1936-1939 se le dio el nombre no oficial y provisional de "urbanizaci‚îú‚îÇn Circo Krone" para que la gente de la ‚îú¬Æpoca pudiera ubicarla. De esta forma, fueron trazadas las calles de Salamanca, Toledo, ‚îú√ºvila y Burgos (un homenaje a algunas de las capitales de provincia que secundaron desde el minuto uno el golpe de Estado del 18 de julio de 1936), y la iniciativa privada se encarg‚îú‚îÇ de la promoci‚îú‚îÇn inmobiliaria de las viviendas y bajos comerciales, con precios de venta al p‚îú‚ïëblico de 225.000 pesetas la casa entera (como anuncia el cartel de primer t‚îú¬Ærmino, a la derecha) y 20.000 el piso...', 1941, 1941, 1941, 'Anos 40', 'UNIVERSIDAD', 41.64776700, -0.89573900, '0101000020E6100000490ED8D5E4A9ECBFCA367007EAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52201208707.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52201208707.webp', 'https://www.flickr.com/photos/zaragozaantigua/52201208707/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22059, 'Puente de los Gitanos 1951', 'Ayuntamiento de Zaragoza/Archivo Mora. Junio 1951. "Calle de Juan Pablo Bonet. Puente sobre el R‚îú¬°o Huerva". Este puente se denomin‚îú‚îÇ originalmente "de la V‚îú¬°a Transversal", por estar situado en una nueva calle que enlazaba el ensanche de Miralbueno con el paseo de Sagasta. Se construy‚îú‚îÇ donde antes hubo una pasarela de hierro y madera, denominada de "Castillo" por enlazar la f‚îú√≠brica as‚îú¬° denominada, con el Camino del S‚îú√≠bado. Se comenzaron las obras del puente el 1 de febrero de 1932. Cost‚îú‚îÇ al Ayuntamiento 800.000 pts., y fue inaugurado sin ceremonia oficial el 1 de septiembre de 1933. Su construcci‚îú‚îÇn, hecha por la Sociedad "Angel A‚îú¬°sa y Hermano", es mixta de sillarejo de piedra de Calatorao en pilas y tajamares, y hormig‚îú‚îÇn armado. Est‚îú√≠ formado por 3 tableros que configuran un espacio de 52 m. de largo, y 20 m. de ancho (12 para calzada y 4 para cada acera). Con el tiempo, ese nombre cay‚îú‚îÇ en el olvido, y la gente comenz‚îú‚îÇ a llamarlo "de los gitanos" porque en los a‚îú‚ñíos 40 y 50 n‚îú‚îÇmadas de ese pueblo a su paso por Zaragoza acampaban temporalmente bajo ‚îú¬Æl. En los a‚îú‚ñíos 60, cuando la zona estaba ya bastante urbanizada, a caballo entre el paseo del General Mola y el paseo de Fernando el Cat‚îú‚îÇlico, se le dio oficialmente el imperial nombre de "puente del Emperador Augusto", aunque el nombre no cal‚îú‚îÇ entre la gente, para cabreo de la Zaragoza oficialista. Hasta nuestros d‚îú¬°as.', 1951, 1951, 1951, 'Anos 50', 'UNIVERSIDAD', 41.64077500, -0.88974700, '0101000020E610000001DA56B3CE78ECBF158C4AEA04D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14931198266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14931198266.webp', 'https://www.flickr.com/photos/zaragozaantigua/14931198266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22126, '&quot;V‚îú¬°a Verde&quot; 1959', 'Imagen de las obras de establecimiento de la doble v‚îú¬°a ferroviaria entre las estaciones de Campo Sepulcro y Miraflores, 3.7 kil‚îú‚îÇmetros de "zanja" que pronto se convertir‚îú¬°a en "trinchera" mental. Al fondo, el puente con t‚îú‚ïënel bajo el paseo de Calvo Sotelo. Desde all‚îú¬° proven‚îú¬°an los directos a Barcelona que paraban en Campo Sepulcro; daba continuidad rodada hacia el paseo de Fernando el Cat‚îú‚îÇlico, a la izquierda; y permit‚îú¬°a al brazal bajo de la acequia de la Romareda seguir su antiguo fluir hacia el "centro", a la derecha. El puente bajo el que se ha capturado esta imagen era denominado "de la V‚îú¬°a Verde" desde su construcci‚îú‚îÇn all‚îú√≠ por 1911, y estaba tendido junto a la margen izquierda del r‚îú¬°o Huerva, permitiendo la continuidad de tr‚îú√≠nsito por la ribera, en forma de paseo, desde el puente de la V‚îú¬°a Perimetral, o del Emperador Augusto, o de los Gitanos, m‚îú√≠s al sur. Fuente visual: AMZ.', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.64390100, -0.89126900, '0101000020E61000003509DE904685ECBF4C6E14596BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23121869781.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23121869781.webp', 'https://www.flickr.com/photos/zaragozaantigua/23121869781/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22131, 'P.‚î¨‚ïë de Fernando el Cat‚îú‚îÇlico c.1955', '"Zaragoza. Avenida Fernando el Cat‚îú‚îÇlico". Un ins‚îú‚îÇlito vistazo desde las alturas del n‚î¨‚ïë 34 del paseo de Calvo Sotelo, muy despejado antes de la construcci‚îú‚îÇn de la macizada manzana entre Dato-Doctor Cerrada-Calvo Sotelo, en direcci‚îú‚îÇn hacia Fernando el Cat‚îú‚îÇlico. Los huecos entre edificios se corresponden con solares a‚îú‚ïën sin edificar, en una zona de la ciudad que entonces parec‚îú¬°a muy lejana del "centro", y resultaba dif‚îú¬°cil pensar que la ciudad llegara a extenderse mucho m‚îú√≠s en esta direcci‚îú‚îÇn. En primer t‚îú¬Ærmino, a la derecha, el desemboque de la calle Ricla en la de Doctor Cerrada. Casi en el centro de la imagen, y tras la trinchera del ferrocarril de los directos Madrid-Barcelona, la esquina achaflanada del cine "Gran V‚îú¬°a". Al fondo, a la izquierda, emerge borrosa la torre del recinto de la Feria de Muestras. Un tranv‚îú¬°a de la l‚îú¬°nea 11 "Parque" regresa hacia la plaza de Espa‚îú‚ñía. Fuente visual: Editorial Garrabella www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.64532400, -0.89071700, '0101000020E61000002CB81FF0C080ECBF76A911FA99D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23761608172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23761608172.webp', 'https://www.flickr.com/photos/zaragozaantigua/23761608172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22193, 'Puente F.C. sobre Huerva 1959', 'Imagen capturada durante las obras de establecimiento de la doble v‚îú¬°a ferroviaria entre las estaciones de Campo Sepulcro y Miraflores (l‚îú¬°nea de Barcelona), y centrada en el desdoble del puente del ferrocarril sobre el r‚îú¬°o Huerva. Se ha terminado de asegurar la primera de las nuevas plataformas sobre las que luego se instalar‚îú√≠ el tendido ferroviario. A su inmediata izquierda, el paso antiguo, con los protectores laterales, que ser‚îú√≠ posteriormente desmantelado. Cuando la obra est‚îú¬Æ finalizada, todo ser‚îú√≠ soterrado. Al fondo, y a la izquierda, vista de la pasarela peatonal de la calle Zumalac‚îú√≠rregui. En el centro de la imagen, antiguas parcelas recayentes a esa calle Fuente visual: Archivo Municipal de Zaragoza.', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32807286703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32807286703.webp', 'https://www.flickr.com/photos/zaragozaantigua/32807286703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22199, 'Puente de la V‚îú¬°a Verde 1959', 'Imagen capturada durante las obras de establecimiento de la doble v‚îú¬°a ferroviaria entre las estaciones de Campo Sepulcro y Miraflores (l‚îú¬°nea de Barcelona), y centrada en el puente de la V‚îú¬°a Verde, construido en 1911 junto a la margen izquierda del r‚îú¬°o Huerva, y que daba continuidad de tr‚îú√≠nsito por la ribera, en forma de paseo, desde el puente de la V‚îú¬°a Perimetral, o del Emperador Augusto, o de los Gitanos, m‚îú√≠s al sur, hasta el paseo de Calvo Sotelo. A la derecha, por donde se realiza el ensanchamiento de la zanja, y arriba, al nivel de la calle, el Instituto Nacional de Ense‚îú‚ñíanza Media √î√á¬£Goya√î√á√ò estaba a punto de ser inaugurado oficialmente. Un poco m‚îú√≠s adelante, a la izquierda del caminante entre los ra‚îú¬°les, el tendido ferroviario salva el r‚îú¬°o Huerva mediante un puentecillo que tambi‚îú¬Æn ser‚îú√≠ desdoblado. Al fondo, brumoso panorama de la margen derecha del r‚îú¬°o, en el entorno de las calles de Moriones, Benavente, y el camino del S‚îú√≠bado. Posteriormente, todo este espacio ser‚îú√≠ cubierto, y desde 2012 aqu‚îú¬° se encuentra la estaci‚îú‚îÇn ferroviaria de Zaragoza-Goya, para servicios de cercan‚îú¬°as, y media distancia. Fuente visual: Archivo Municipal de Zaragoza.', 1959, 1959, 1959, 'Anos 50', 'UNIVERSIDAD', 41.64369600, -0.89071700, '0101000020E61000002CB81FF0C080ECBF73486AA164D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33554752576.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33554752576.webp', 'https://www.flickr.com/photos/zaragozaantigua/33554752576/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22243, 'C‚î¨‚ïë del S‚îú√≠bado c.1955', 'Imagen capturada desde la altura de una antigua parcela del lado de los pares del camino del S‚îú√≠bado poco despu‚îú¬Æs del cruce con la calle de la Luz, que en esta fotograf‚îú¬°a aparece luminosa en el centro de la escena formando una "replaceta" donde confluyen tanto el camino del S‚îú√≠bado, desde la izquierda, como la calle de Anselmo Gasc‚îú‚îÇn de Gotor desde el fondo y por la derecha, tras pasar por la calle del Porvenir. A la derecha e inmediato, reciente inmueble esquinero entre el camino y la calle de la Luz. A la sombra y en el centro del terroso camino, luego redenominado calle del Arzobispo Dom‚îú¬Ænech y finalmente desdoblado como calle del Arzobispo Morcillo, vecinos de la Explanada del S‚îú√≠bado en torno a una orquesta durante las fiestas de la barriada.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63829800, -0.88967800, '0101000020E6100000E00F3FFF3D78ECBF158DB5BFB3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51267739476.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51267739476.webp', 'https://www.flickr.com/photos/zaragozaantigua/51267739476/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22244, 'C.‚î¨‚ïë del S‚îú√≠bado c.1957', 'Imagen capturada en el tramo del camino del S‚îú√≠bado inmediato al espacio donde a la izquierda y fuera de plano estaba prevista la construcci‚îú‚îÇn del Grupo Salduba, con el despejado aspecto de campos de cultivo y torre agr‚îú¬°cola entre el riego del S‚îú√≠bado y la trinchera del r‚îú¬°o Huerva. Al fondo y tras el parque de Primo de Rivera, despunta la torre-mirador de la Feria Nacional de Muestras. A la derecha, traseras de las viviendas proyectadas por el arquitecto Antonio Ch‚îú‚îÇliz Alcrudo en la calle del Arzobispo Apaolaza, y la ampliaci‚îú‚îÇn de la Editorial Luis Vives S.A.', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63713500, -0.89288500, '0101000020E6100000C3D842908392ECBF8811C2A38DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51311705514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51311705514.webp', 'https://www.flickr.com/photos/zaragozaantigua/51311705514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22245, 'Casas baratas Huerva c.1957', 'Imagen capturada desde las traseras de una antigua parcela del lado de los pares del camino del S‚îú√≠bado poco despu‚îú¬Æs del cruce con la calle de la Luz. Tras los ‚îú√≠rboles y las parcelas de primer t‚îú¬Ærmino que en descenso llevan hasta la trinchera del r‚îú¬°o Huerva, pasando por las calles de Mario Lasala Vald‚îú¬Æs y la propia del R‚îú¬°o Huerva, vista excepcional a la derecha de las naves industriales de la antigua f‚îú√≠brica textil de los Hijos de C‚îú√≠ndido Castillo, al otro lado del r‚îú¬°o y ribere‚îú‚ñía a ‚îú¬Æl. Despu‚îú¬Æs, viviendas de las Casas Baratas del Huerva recayentes a la calle de Domingo y Francisco La Ripa, y vista de las incipientes construcciones en el entorno de la calle de San Juan de la Cruz, donde destaca la torre de la parroquia del Carmen y de San Jos‚îú¬Æ, entre las calles de Luis Ram de Viu y de Santa Teresa de Jes‚îú‚ïës.', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.64044700, -0.89141600, '0101000020E61000004432E4D87A86ECBF21E9D32AFAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51317689291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51317689291.webp', 'https://www.flickr.com/photos/zaragozaantigua/51317689291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22368, 'Avenida de Goya c.1966', 'Postal. Ediciones Arribas. Vista de la avenida de Goya en el cruce con los paseos de Calvo Sotelo y de Fernando el Cat‚îú‚îÇlico. El aparcamiento en superficie del primer t‚îú¬Ærmino est‚îú√≠ feliz y actualmente ocupado por la estaci‚îú‚îÇn ferroviaria de cercan‚îú¬°as Zaragoza-Goya.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64390100, -0.89126900, '0101000020E61000003509DE904685ECBF4C6E14596BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21445166159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21445166159.webp', 'https://www.flickr.com/photos/zaragozaantigua/21445166159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22379, 'Vista a‚îú¬Ærea Parque Grande 1964', 'Vista a‚îú¬Ærea del parque Primo de Rivera, con el Cabezo de Buenavista y su Jard‚îú¬°n de Invierno. Al fondo la Residencia Sanitaria Jos‚îú¬Æ Antonio o Casa Grande y el barrio de la Romareda. Fuente: Colecci‚îú‚îÇn Rafael Margal‚îú¬Æ.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22303469792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22303469792.webp', 'https://www.flickr.com/photos/zaragozaantigua/22303469792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22388, 'Padre Claret c.1960', 'Imagen de la trinchera del ferrocarril de los directos Madrid-Barcelona procedente de la estaci‚îú‚îÇn de Campo Sepulcro, en la zona entre los paseos de Teruel (a la espalda) y el de Calvo Sotelo (girando al fondo, hacia la izquierda). A ambos lados de este tramo se les denominaba "Padre Antonio Mar‚îú¬°a Claret". La imagen ha sido capturada desde uno de los pasos peatonales que salvaban la trinchera, a la altura de la calle Antonio C‚îú√≠novas. Delante est‚îú√≠ el que comunicaba los dos tramos dispares de la calle del Carmen. M‚îú√≠s adelante, al fondo, destaca reci‚îú¬Æn terminado el nuevo e imponente "Templo o Santuario del Coraz‚îú‚îÇn de Mar‚îú¬°a", de la Congregaci‚îú‚îÇn de los Misioneros Hijos del Inmaculado Coraz‚îú‚îÇn de Mar‚îú¬°a, o "Claretianos". Unos pocos a‚îú‚ñíos m‚îú√≠s tarde, este entorno sufrir‚îú√≠ una interesante metamorfosis cuando se proceda al soterramiento de las v‚îú¬°as del tren, y el nuevo vial resultante sea denominado "Avenida de Goya", como otra nueva gran v‚îú¬°a para el tr‚îú√≠fico rodado. De rebote, la preexistente calle de Goya, continuacion de la de Contamina, deber‚îú√≠ ser redenominada como "Juseppe Mart‚îú¬°nez".', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.64645900, -0.89370000, '0101000020E610000029ED0DBE3099ECBF399A232BBFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22713941820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22713941820.webp', 'https://www.flickr.com/photos/zaragozaantigua/22713941820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22393, 'Avenida Goya 1966', 'Obras de construcci‚îú‚îÇn de la avenida de Goya, soterrando las v‚îú¬°as del ferrocarril, que en este punto pasan sobre el r‚îú¬°o Huerva. Al fondo, el Instituto Goya. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22755427039.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22755427039.webp', 'https://www.flickr.com/photos/zaragozaantigua/22755427039/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22419, 'Parque Grande c.1967', 'Nocturna imagen, con vista desde el Cabezo de Buenavista, del acceso al parque Primo de Rivera por el puente del trece de setiembre, convertida en entra‚îú‚ñíable postal por la Editorial Garc‚îú¬°a Garrabella. Al fondo, los grandes hitos de la moderna ciudad en esta alejada zona del centro: la "Residencia Sanitaria Jose Antonio", el campo municipal de la Romareda, y el recinto de la Feria de Muestras. Junto al aparcado veh‚îú¬°culo, unos a‚îú‚ñíos despu‚îú¬Æs ser‚îú√≠ reinstalada la maravillosa fuente luminosa de la plaza de Para‚îú¬°so, cuando la convivencia con el tr‚îú√≠fico rodado a motor de explosi‚îú‚îÇn sea insostenible. Por eso, para la mayor‚îú¬°a de ciudadanos, este lugar, el Parque, es una especie de "vertedero", o "contenedor" de lo que la ciudad expulsa. Una especie de exilio. Que le pregunten a la fuente d‚îú‚îÇnde querr‚îú¬°a estar. Fuente: www.ebay.es/', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.63440400, -0.89428200, '0101000020E6100000DCD8EC48F59DECBFCE39782634D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26304391624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26304391624.webp', 'https://www.flickr.com/photos/zaragozaantigua/26304391624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22421, 'Parque Primo de Rivera c.1968', 'Fuentes del paseo de San Sebasti‚îú√≠n del parque Primo de Rivera. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27142460830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27142460830.webp', 'https://www.flickr.com/photos/zaragozaantigua/27142460830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22484, 'Calle de Benavente 1968', 'Imagen capturada al final de la calle de Benavente durante las obras de urbanizaci‚îú‚îÇn del entorno de la moderna avenida de Goya. A la derecha e inmediatos, pronunciados desniveles y terraplenes que descienden hacia el r‚îú¬°o Huerva desde un estrecho vial a‚îú‚ïën sin nombre que conduce, al fondo, a las ruinas de la antigua f‚îú√≠brica de curtidos "La Progresiva", en un ramal del que fuera camino del S‚îú√≠bado. A la izquierda y vecinos del moderno gran bloque esquinero que centra la imagen, perduran algunas de las antiguas parcelas de la zona, e incluso parece destacarse la chimenea de la vieja f‚îú√≠brica de tejidos de punto de Santiago Vicente, tambi‚îú¬Æn en el antiguo camino del S‚îú√≠bado, en un tramo ya redenominado calle del Arzobispo Dom‚îú¬Ænech. Fuente visual: AMZ.', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.64313500, -0.89003000, '0101000020E610000025AFCE31207BECBFDCF4673F52D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40148132124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40148132124.webp', 'https://www.flickr.com/photos/zaragozaantigua/40148132124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22503, 'Carmelitas, c.1965', 'Imagen centrada en la iglesia parroquial de San Juan de la Cruz, de la orden de los carmelitas descalzos de San Jos‚îú¬Æ, establecida desde 1945 en el n‚î¨‚ïë 8 de esta hom‚îú‚îÇnima calle, entre las calles de Ram de Viu (a la izquierda), y la de Santa Teresa de Jes‚îú‚ïës (a la derecha).', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64106400, -0.89252100, '0101000020E61000006DC83F33888FECBF4C5299620ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49918928306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49918928306.webp', 'https://www.flickr.com/photos/zaragozaantigua/49918928306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22577, 'Calvo Sotelo c.1975', 'Postal Comercial Jos‚îú√≠n. Vista del paseo de Calvo Sotelo en su confluencia con la Avenida Goya, tomada desde Fernando el Cat‚îú‚îÇlico.', 1975, 1975, 1975, 'Anos 70', 'UNIVERSIDAD', 41.64436600, -0.89170300, '0101000020E6100000C3D7D7BAD488ECBFC153C8957AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15536105155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15536105155.webp', 'https://www.flickr.com/photos/zaragozaantigua/15536105155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22581, 'Padres Pa‚îú‚ïëles 1973', 'Archivo Municipal. Gerardo Sancho Ramo. 25/02/1973. Imagen del piqueteo del Convento-Residencia de los Padres Pa‚îú‚ïëles de la Avenida de Goya, en la manzana entre el Paseo de Teruel y la calle de C‚îú√≠novas. La valla se‚îú‚ñíala el punto desde el que las v‚îú¬°as del ferrocarril estaban ya soterradas desde 1960. La Congregaci‚îú‚îÇn de la Misi‚îú‚îÇn, llamada en Espa‚îú‚ñía de los PP. Pa‚îú‚ïëles, se estableci‚îú‚îÇ en esta ubicaci‚îú‚îÇn de Zaragoza en 1924, cuando el Paseo de Teruel era la "Carretera de Zaragoza a Teruel", como Casa Principal de la ciudad. Vendieron la titularidad del terreno en 1972 por motivos econ‚îú‚îÇmicos, y sobre el solar se edificaron los actuales bloques de viviendas del n‚îú‚ïëmero 96 de la avenida de Goya. Fuente Visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64744300, -0.89359300, '0101000020E6100000A7E7DD585098ECBF17838769DFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15584999125.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15584999125.webp', 'https://www.flickr.com/photos/zaragozaantigua/15584999125/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22607, 'Calle Santander 1970', 'Imagen un tanto encharcada de la calle de Santander en su parte m‚îú√≠s cercana al pretil y paso sobre las v‚îú¬°as del ferrocarril. El aparente marasmo circulatorio no es tal: los veh‚îú¬°culos est‚îú√≠n aparcados seg‚îú‚ïën una ordenaci‚îú‚îÇn flexible, abierta, y tolerante, que se beneficia de la ausencia, precisamente, de tr‚îú√≠fico rodado. Al otro lado de las v‚îú¬°as, Anselmo Clav‚îú¬Æ presenta el tel‚îú‚îÇn de fondo del antiguo edificio de la Casa de Convalecientes, que desde finales de los a‚îú‚ñíos cincuenta estaba ocupado por el Colegio Polit‚îú¬Æcnico Nuestra Se‚îú‚ñíora del Pilar. Por encima, sobresalen los grandes bloques del paseo de Teruel, que en poco tiempo tendr‚îú¬°an unos replicantes sobre el solar de este interesante edificio dise‚îú‚ñíado por Julio Bravo. Interesante, pero antiguo, y peque‚îú‚ñío. Muy peque‚îú‚ñío. Fuente visual: Archivo P‚îú‚ïëblico Municipal.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.64878500, -0.89362600, '0101000020E6100000965E9B8D9598ECBF53910A630BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19023617963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19023617963.webp', 'https://www.flickr.com/photos/zaragozaantigua/19023617963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22691, 'Julio Cejador Frauca 1977', 'Imagen de la calle Julio Cejador Frauca (antiguo Camino Viejo de Cuarte), capturada casi ya desde el paseo de Mariano Renovales, con una interesante visual del periurbano y solariego estado de las cosas desde este punto y hasta la parcela del n‚îú‚ïëmero 10-12, donde una d‚îú¬Æcada despu‚îú¬Æs se abrir‚îú√≠ un nuevo vial denominado "Los Jilgueros". A la derecha, inmediatas, las traseras de la veterana harinera "La Imperial", con notable fachada al Canal Imperial, unos metros m‚îú√≠s arriba. Al fondo, el arranque de esta calle desde el paseo de Ruise‚îú‚ñíores, en el punto de acceso al modernizado complejo del "Colegio Pompiliano". Por detr‚îú√≠s de ‚îú¬Æste, emerge por verticalidad la estructura del destacable "Edificio Ruise‚îú‚ñíores", o "Casa de los Peces" del paseo. Fuente visual: amable aportaci‚îú‚îÇn personal de Pablo Vald‚îú¬Æs.', 1977, 1977, 1977, 'Anos 70', 'UNIVERSIDAD', 41.63485200, -0.89230500, '0101000020E61000003DD52137C38DECBF6DE690D442D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26918478456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26918478456.webp', 'https://www.flickr.com/photos/zaragozaantigua/26918478456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22738, 'Plaza San Francisco c.1973', 'Un tranv‚îú¬°a de la l‚îú¬°nea 11, "Parque-San Jos‚îú¬Æ", pasa por la plaza de San Francisco, procecente del parque Primo de Rivera. Fuente: Heraldo de Arag‚îú‚îÇn.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64066800, -0.89493700, '0101000020E61000000B5F5FEB52A3ECBFFFCBB56801D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31496043090.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31496043090.webp', 'https://www.flickr.com/photos/zaragozaantigua/31496043090/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22787, 'P.‚î¨‚ïë Fernando el Cat‚îú‚îÇlico 1976', 'Imagen capturada en el arranque del paseo de Fernando el Cat‚îú‚îÇlico desde el cruce con la avenida de Goya. Perduran sobre el firme los rieles de la tranviaria l‚îú¬°nea 11 Parque-San Jos‚îú¬Æ, clausurada a principios de ese a‚îú‚ñío. El peatonal and‚îú¬Æn central del paseo muestra su conversi‚îú‚îÇn, con el benepl‚îú√≠cito municipal, en aparcamiento en superficie para veh‚îú¬°culos privados. A la derecha, el cine Gran V‚îú¬°a. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.64426000, -0.89189000, '0101000020E61000005F24B4E55C8AECBF7C0F971C77D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38505128251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38505128251.webp', 'https://www.flickr.com/photos/zaragozaantigua/38505128251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22799, 'P.‚î¨‚ïë de Ruise‚îú‚ñíores 1971', 'Imagen capturada en el paseo de Ruise‚îú‚ñíores, a la altura del ingreso al nuevo complejo edilicio en construcci‚îú‚îÇn del n‚î¨‚ïë 26, edificado sobre el solar dejado por el antiguo Colegio Pompiliano de las Madres escolapias. A la derecha, el inmediato n‚î¨‚ïë 24, hotelito proyectado por Francisco Albi‚îú‚ñíana para Victoriano Carbon‚îú¬Æ, cuyo muro perimetral ha sido afectado por el derribo, y un alba‚îú‚ñíil se encuentra reponiendo el tramo m‚îú√≠s esquinero de ‚îú¬Æste. Unos a‚îú‚ñíos despu‚îú¬Æs esta antigua casa tambi‚îú¬Æn ser‚îú√≠ derribada para dar paso a nuevas viviendas de la elite local, y este peque‚îú‚ñío y reconstruido tramo del muro de ladrillo ser‚îú√≠ la ‚îú‚ïënica traza que llegar‚îú¬°a hasta nuestros d‚îú¬°as. Al fondo y a la izquierda, tras la arboleda y la acequia al aire de San Jos‚îú¬Æ, el Grupo Salduba. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1971, 1971, 1971, 'Anos 70', 'UNIVERSIDAD', 41.63635900, -0.88949400, '0101000020E6100000889FFF1EBC76ECBFF4C1323674D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46724937411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46724937411.webp', 'https://www.flickr.com/photos/zaragozaantigua/46724937411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22842, 'Cascada ornamental 1989', 'Nuestra Zaragoza, agosto de 1989. Construcci‚îú‚îÇn de la cascada ornamental con escalinata a los pies de la estatua de Alfonso I en el Cabezo. Supuso protestas ecologistas por la eliminaci‚îú‚îÇn de arbolado.', 1989, 1989, 1989, 'Anos 80', 'UNIVERSIDAD', 41.63426300, -0.89406300, '0101000020E6100000680932022A9CECBF0B08AD872FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15008550386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15008550386.webp', 'https://www.flickr.com/photos/zaragozaantigua/15008550386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22858, 'Cabezo de Buena Vista 1987', 'Luis M‚îú¬°nguez. 1987. Imagen del Parque Primo de Rivera desde la torre-mirador de la Feria de Muestras. Este pulm‚îú‚îÇn "verde" (sentido figurado) data de 1927, aunque el foco de la captura se fija especialmente en el Cabezo de Buena Vista, una zona que ya en 1925 hab‚îú¬°a sido modificada, pues de apenas un monte pelado, se planific‚îú‚îÇ un espacio lleno de olmos, acacias y pinos de repoblaci‚îú‚îÇn. Pronto se convirti‚îú‚îÇ en el mirador natural de la ciudad, al poco se instal‚îú‚îÇ all‚îú¬° al Batallador y su mascota, y la gente iba a pasar un rato agradable. En la imagen, aspecto del final del Paseo de San Sebasti‚îú√≠n, y su entronque con la Avenida de los Bearneses, en tiempos en que para llegar al Cabezo no hab‚îú¬°a escaleras blancas. Al fondo, tel‚îú‚îÇn de fondo del transcanalino barrio de Venecia. Entre el verdor, a la derecha de la estatua, un par de a‚îú‚ñíos antes se hab‚îú¬°a inaugurado un monumento a los aragoneses confinados en campos de concentraci‚îú‚îÇn nazi-alemanes. No se le ve, como ahora.', 1987, 1987, 1987, 'Anos 80', 'UNIVERSIDAD', 41.63426000, -0.89396400, '0101000020E61000009CA4F9635A9BECBF9A94826E2FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15630227287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15630227287.webp', 'https://www.flickr.com/photos/zaragozaantigua/15630227287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22936, 'Cabezudos ap‚îú‚îÇcrifos c.1985', 'Foto: Jos‚îú¬Æ Carlos Rodr‚îú¬°guez. Manifestaci‚îú‚îÇn anti OTAN animada por cabezudos no pertenecientes a la comparsa municipal, a su paso por el paseo de Fernando el Cat‚îú‚îÇlico, a la altura del 33. Est‚îú√≠n a punto de llegar a la plaza de San Francisco. Al fondo se abre a la derecha la calle de San Juan de la Cruz. Fuente: www.facebook.com/photo.php?fbid=1401819319859258&set=...', 1985, 1985, 1985, 'Anos 80', 'UNIVERSIDAD', 41.64155000, -0.89425000, '0101000020E610000004560E2DB29DECBFD95F764F1ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32503616501.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32503616501.webp', 'https://www.flickr.com/photos/zaragozaantigua/32503616501/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23052, 'Gran V‚îú¬°a 1994', 'Imagen capturada desde la altura del inmueble del n‚î¨‚ïë 2 del paseo de Fernando el Cat‚îú‚îÇlico y centrada en la rotonda automovil‚îú¬°stica situada en el estrat‚îú¬Ægico punto donde confluyen el arranque de este paseo, el final de la Gran V‚îú¬°a, y se cruza la avenida de Goya. Para embellecer este duro entorno, cuando en 1995 gan‚îú‚îÇ las elecciones municipales el Partido Popular de Luisa Fern‚îú√≠ndez Rudi, se baraj‚îú‚îÇ la posibilidad de ubicar aqu‚îú¬° la estatua ecuestre del general Jos‚îú¬Æ Palafox realizada en bronce por Ignacio Rodr‚îú¬°guez Ruiz (I‚îú‚ñíaki), que finalmente ser‚îú¬°a inaugurada a finales del a‚îú‚ñío 2000 por el sustituto alcalde Jos‚îú¬Æ Atar‚îú¬Æs en la moderna plaza de Jos‚îú¬Æ Mar‚îú¬°a Forqu‚îú¬Æ. En la ubicaci‚îú‚îÇn de la imagen se instalar‚îú¬°a una recurrente fuentecilla.', 1994, 1994, 1994, 'Anos 90', 'UNIVERSIDAD', 41.64425500, -0.89192000, '0101000020E61000000ABFD4CF9B8AECBF6AA4A5F276D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50443828023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50443828023.webp', 'https://www.flickr.com/photos/zaragozaantigua/50443828023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23054, 'P.‚î¨‚ïë de Teruel 1994', 'Imagen del paseo de Teruel, poco antes de su desemboque en la avenida de Francisco de Goya, capturada tras el derribo, a la izquierda, del inmueble del n‚î¨‚ïë 37 y centrada en la antigua vivienda unifamiliar del n‚î¨‚ïë 39 que poco despu‚îú¬Æs ser‚îú¬°a tambi‚îú¬Æn derribada, y sobre cuyos solares se levantar‚îú¬°a poco despu‚îú¬Æs el actual inmueble del n‚î¨‚ïë 37-39 del paseo. La escala de la casa y el patio de acceso la se‚îú‚ñíalaban como una reliquia de otras ‚îú¬Æpocas que, lamentablemente, no sobrevivi‚îú‚îÇ a esta d‚îú¬Æcada.', 1994, 1994, 1994, 'Anos 90', 'UNIVERSIDAD', 41.64791100, -0.89306800, '0101000020E61000000455A3570394ECBFFDDB65BFEED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50446016076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50446016076.webp', 'https://www.flickr.com/photos/zaragozaantigua/50446016076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23080, 'Calle Santa Teresa 2000', 'A finales de los a‚îú‚ñíos 20 del pasado siglo, en un vial del entonces nuevo ensanche de Miralbueno, que tras el 18 de julio de 1936 ser‚îú√≠ denominado calle Santa Teresa de Jes‚îú‚ïës, fue construida una casa en estilo racionalista (dise‚îú‚ñío de Secundino Zuazo) que se convirti‚îú‚îÇ en residencia de la familia del fil‚îú‚îÇlogo Jos‚îú¬Æ Manuel Blecua (nacido en 1939). Se le adjudic‚îú‚îÇ el n‚î¨‚ïë 37 de la calle. Al comienzo de la d‚îú¬Æcada de los 90, su propietaria vendi‚îú‚îÇ el terreno a una constructora para ser piqueteada la casa, y aprovechar con m‚îú√≠s rentabilidad econ‚îú‚îÇmica su hasta entonces desperdiciado potencial porcentaje de edificabilidad. Algunos ciudadanos, entre 1994 y 2000, intentaron impedirlo, pero la ‚îú‚ïëltima palabra municipal (Gerencia de Urbanismo) dio luz verde al progreso, y el 21 de abril de 2000 esta casita fue encaminada hacia su transformaci‚îú‚îÇn en un bloque de cinco pisos y diez apartamentos que fue denominado "Edificio Blecua", otro ejemplo de la compatibilidad entre la ecolog‚îú¬°a patrimonial y el desarrollo urban‚îú¬°stico en esta ciudad. Fuente: blogs.heraldo.es/', 2000, 2000, 2000, 'Siglo XXI', 'UNIVERSIDAD', 41.63945200, -0.89420500, '0101000020E6100000056EDDCD539DECBF4FAE2990D9D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17046904979.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17046904979.webp', 'https://www.flickr.com/photos/zaragozaantigua/17046904979/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23153, 'Avenida Goya 2009', 'Foto: V‚îú¬°ctor Lax. Fuente en el cruce de la avenida de Goya (izquierda) con el fin de la Gran V‚îú¬°a (derecha), instalada en la segunda mitad de los noventa. Ser‚îú√≠ eliminada en 2011 con motivo de la implantaci‚îú‚îÇn del tranv‚îú¬°a y de la construcci‚îú‚îÇn de la estaci‚îú‚îÇn de cercan‚îú¬°as Zaragoza-Goya, inaugurada en 2012. Fuente: Heraldo de Arag‚îú‚îÇn.', 2009, 2009, 2009, 'Siglo XXI', 'UNIVERSIDAD', 41.64426000, -0.89189000, '0101000020E61000005F24B4E55C8AECBF7C0F971C77D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32342265053.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32342265053.webp', 'https://www.flickr.com/photos/zaragozaantigua/32342265053/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23165, 'Avenida Goya 2009', 'Foto: Javier Cebollada/ Agencia EFE. Vista de la avenida de Goya en marzo de 2009, desde su cruce con la calle de Calatayud. A la izquierda, iglesia parroquial del Coraz‚îú‚îÇn de Mar‚îú¬°a, en el n‚îú‚ïëmero 67. A la derecha, obras en los edificios de la calle de las Cortes de Arag‚îú‚îÇn 32 y la avenida de Goya 60. Este ‚îú‚ïëltimo inmueble ser‚îú√≠ recrecido durante el proceso. Sobre el andamio, publicidad de la Uni‚îú‚îÇn de Ateos y Librepensadores, colocada tras la negativa de TUZSA a incluir en los autobuses urbanos el eslogan "Probablemente dios no existe. Deja de preocuparte y disfruta la vida". Se trataba de una campa‚îú‚ñía nacida en el Reino Unido en 2008, promovida por la British Humanist Association (1896). Fuente: Heraldo de Arag‚îú‚îÇn.', 2009, 2009, 2009, 'Siglo XXI', 'UNIVERSIDAD', 41.64490900, -0.89280200, '0101000020E610000063B5F97FD591ECBFB2F2CB608CD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32653934190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32653934190.webp', 'https://www.flickr.com/photos/zaragozaantigua/32653934190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23212, 'Avenida Goya 2011', 'Foto: V‚îú¬°ctor Lax. Vista de la avenida de Francisco de Goya, tramo comprendido entre la Gran V‚îú¬°a (izquierda) y el paseo de Sagasta (al fondo). Se est‚îú√≠n efectuando las obras de construcci‚îú‚îÇn de la estaci‚îú‚îÇn ferroviaria Zaragoza-Goya, que ser‚îú√≠ inaugurada en abril de 2012. En primer tramo, obras del tranv‚îú¬°a. Fuente: Heraldo de Arag‚îú‚îÇn.', 2011, 2011, 2011, 'Siglo XXI', 'UNIVERSIDAD', 41.64398400, -0.89128700, '0101000020E6100000CF328B506C85ECBFDA9255116ED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35794892414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35794892414.webp', 'https://www.flickr.com/photos/zaragozaantigua/35794892414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23223, 'Colegio Jes‚îú‚ïës y Mar‚îú¬°a 2016', 'Vista desde la avenida de Goya del solar del antiguo colegio de las religiosas de Jes‚îú‚ïës y Mar‚îú¬°a, fundado en 1930 y en desuso desde 1997, cuando se constituy‚îú‚îÇ el colegio de los jesuitas unificado en el edificio de la Romareda y se vendi‚îú‚îÇ el complejo a la promotora Bilbao Patrimonial Wilcox, de la familia Llorente Sanz. Un solar de casi 9.000 m2 entre la avenida de Goya y la calle de las Cortes de Arag‚îú‚îÇn, cuyo estatus ya en 2002 y 2008 se ide‚îú‚îÇ permutar, de usos sociales (deportivos, culturales, educativos, sanitarios, asistenciales, religiosos o de espect‚îú√≠culos) a urban‚îú¬°sticos (residenciales), por parte del Gobierno municipal del PSOE. En 2016, con Zaragoza en Com‚îú‚ïën al frente del Ayuntamiento, se neg‚îú‚îÇ la recalificaci‚îú‚îÇn a los propietarios, que intentaban levantar 380 pisos. Ya a finales de 2020, con el Partido Popular, se volvi‚îú‚îÇ a desempolvar el proyecto, inici‚îú√≠ndose los tr‚îú√≠mites para modificar el PGOU vigente (de 2001) con los votos a favor de PP, PSOE, Ciudadanos y Vox. La intentona pretend‚îú¬°a esta vez construir 170 viviendas libres y conseguir de rond‚îú‚îÇn la venta del edificio escolar de 1939 al Ayuntamiento, una vez incrementado su valor tras la permuta y con la carga p‚îú‚ïëblica de su consiguiente rehabilitaci‚îú‚îÇn. En 2024 se inici‚îú‚îÇ el derribo.', 2016, 2016, 2016, 'Siglo XXI', 'UNIVERSIDAD', 41.64617400, -0.89296100, '0101000020E6100000834F73F22293ECBF44C362D4B5D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51247730305.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51247730305.webp', 'https://www.flickr.com/photos/zaragozaantigua/51247730305/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25008, 'C.‚î¨‚ïë de Cuarte 1899', 'Imagen de la f‚îú√≠brica de "peinado" de hilados de lana y confecci‚îú‚îÇn de tejidos de fajas de Joaqu‚îú¬°n Herrero, luego continuada por su hijo, cuya direcci‚îú‚îÇn publicitaria y comercial la situaba en el paseo de Ruise‚îú‚ñíores, si bien su ubicaci‚îú‚îÇn visual parece orientarnos algo m‚îú√≠s cerca del antiguo camino de Cuarte, que es el vial que aparece en la imagen, entre las escalonadas terrazas en descenso desde el nivel del Canal Imperial de Arag‚îú‚îÇn (a la derecha, fuera de plano), junto a la acequia que derivaba agua primero a la f‚îú√≠brica de harinas de Monares, y luego a esta instalaci‚îú‚îÇn textil, para terminar en la acequia de las Adulas, o de San Jos‚îú¬Æ. Fuente visual: posiblemente foto Coyne, en "Arag‚îú‚îÇn Ilustrado" n‚î¨‚ïë 2 (7 de enero de 1899).', 1899, 1899, 1899, 'Siglo XIX', 'UNIVERSIDAD', 41.63487600, -0.89165000, '0101000020E61000000E4FAF946588ECBFF581E49D43D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31634637183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31634637183.webp', 'https://www.flickr.com/photos/zaragozaantigua/31634637183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25991, 'Vista a‚îú¬Ærea El Pilar 1927', 'Foto Gaspar, 1927. Vista a‚îú¬Ærea de la plaza del Pilar de Zaragoza y su entorno. Fuente: La Esfera, 13 de agosto de 1927.', 1927, 1927, 1927, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19850094498.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19850094498.webp', 'https://www.flickr.com/photos/zaragozaantigua/19850094498/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23324, 'Iglesia del Coraz‚îú‚îÇn de Mar‚îú¬°a 1964', 'Fototeca Universidad de Sevilla. Antonio Palau. Agosto de 1964. "Iglesia del Coraz‚îú‚îÇn de Mar‚îú¬°a". La Congregaci‚îú‚îÇn de los Misioneros Hijos del Inmaculado Coraz‚îú‚îÇn de Mar‚îú¬°a, o "Claretianos", llevaban instalados en la ciudad desde 1924, primero en la Avenida Central n‚î¨‚ïë 8 (actual calle Zumalac‚îú√≠rregui), luego en la Avenida Siglo XX n‚î¨‚ïë 37 (actual P‚î¨‚ïë de Cu‚îú¬Ællar), y en 1940 en una peque‚îú‚ñía capilla de la calle del Carmen (en el actual S. Antonio M‚î¨¬¨ Claret n‚î¨‚ïë 9-11). Al comienzo de los a‚îú‚ñíos 50, adquirieron terrenos para construir el "Templo o Santuario del Coraz‚îú‚îÇn de Mar‚îú¬°a", junto a la trinchera del ferrocarril (actual Avenida de Goya n‚î¨‚ïë 65). Las obras comenzaron en 1954, bajo la direcci‚îú‚îÇn del arquitecto Eduardo Lagunilla de Plandolit. En 1956 retomaron el culto ya aqu‚îú¬°, y el templo fue finalizado en mayo de 1964, con la denominaci‚îú‚îÇn de "Parroquia del Coraz‚îú‚îÇn de Mar‚îú¬°a". En este 2014 han cumplido los 50 a‚îú‚ñíos en esa ubicaci‚îú‚îÇn. La imagen ha sido tomada desde la Avenida de Goya, capturando la fachada principal, y un aspecto del lateral que daba al solar hoy ocupado por el bloque de viviendas del n‚î¨‚ïë 67 de la Avenida. Fuente visual: fototeca.us.es/imagen.jsp?id=25794&tipo=v&elto=18... Fuente textual: www.cormariazaragoza.es/?-HISTORIA-PDF-BODAS-DE-ORO-', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.64534400, -0.89340000, '0101000020E610000082E2C798BB96ECBFBD55D7A19AD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15448577199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15448577199.webp', 'https://www.flickr.com/photos/zaragozaantigua/15448577199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23347, 'Av. de Goya 1967', 'Imagen capturada desde cierta altura del despejado tramo final de la moderna avenida de Goya durante la fase de urbanizaci‚îú‚îÇn tras el reciente soterramiento de la l‚îú¬°nea ferroviaria de Barcelona a su paso por la que fuera antigua calle del Padre Claret. A la derecha, manzanas del lado de los pares entre las calles del Carmen, C‚îú√≠novas y el paseo de Teruel, entre las que destaca la del convento-residencia de los PP. Pa‚îú‚ïëles. Al fondo, entorno de la estaci‚îú‚îÇn de Campo Sepulcro Fuente visual: AMZ.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.64645900, -0.89370000, '0101000020E610000029ED0DBE3099ECBF399A232BBFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40881298151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40881298151.webp', 'https://www.flickr.com/photos/zaragozaantigua/40881298151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23386, 'Canal Imperial 1925', 'Imagen convertida en postal por Lucien Roisin, tomada desde la margen derecha del Canal Imperial, en el entorno de la acentuada curva que, hacia la derecha, lo conduce al largo y recto tramo del embarcadero de Venecia, y el puente de Am‚îú¬Ærica. A la izquierda aparece parcialmente el chalet Buenavista y el camino que conduce al cabezo del mismo nombre, en el parque de Buenavista, antes de que el dictador Primo de Rivera lo inaugurara oficialmente. Al fondo, un descenso en pronunciada pendiente nos llevar‚îú¬°a al camino viejo de Cuarte, al del S‚îú√≠bado, y a la acequia de las Adulas, o de San Jos‚îú¬Æ. A la derecha, asoma la fachada de la harinera "La Imperial de Arag‚îú‚îÇn", esquinera con el paseo de Ruise‚îú‚ñíores. En el lugar escogido por Roisin para capturar esta fotograf‚îú¬°a, varias d‚îú¬Æcadas despu‚îú¬Æs ser‚îú√≠ construida una alta pasarela peatonal sobre el Canal para conectar con el barrio de Venecia, que subsiste. Fuente visual: www.todocoleccion.net/', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63268200, -0.89156800, '0101000020E6100000C51F459DB987ECBF4A6249B9FBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30918229051.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30918229051.webp', 'https://www.flickr.com/photos/zaragozaantigua/30918229051/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23394, 'P.‚î¨‚ïë del Canal c.1926', 'Invernal imagen capturada en el paseo del Canal, en la curva tras la que al fondo se eleva el cabezo de Buenavista. A la izquierda, vista de la antigua vivienda unifamiliar en el n‚î¨‚ïë 31 de la V‚îú¬°a de Pignatelli, en el barrio de Venecia. Por el Canal Imperial de Arag‚îú‚îÇn desciende una barca a remos encaminada hacia el embarcadero recreativo ubicado aguas abajo. Tras ella, vivienda del guarda del cabezo de Buenavista, y lateral del chalet de Las Palmeras. A la derecha, fachada canalina de la f‚îú√≠brica de harinas de Monares. En primer t‚îú¬Ærmino, sombra del fot‚îú‚îÇgrafo autor de la instant‚îú√≠nea.', 1926, 1926, 1926, 'Anos 20', 'UNIVERSIDAD', 41.63388000, -0.89067500, '0101000020E610000071AC8BDB6880ECBF53CBD6FA22D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48511149287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48511149287.webp', 'https://www.flickr.com/photos/zaragozaantigua/48511149287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23639, 'Puente V‚îú¬°a Transversal 1933', 'Dentro del Plan de Ensanche de ese a‚îú‚ñío, la Avenida Perimetral estaba previsto que fuera una nueva v‚îú¬°a urbana con que enlazar las carreteras de Madrid y de Castell‚îú‚îÇn sin pasar por el centro de la ciudad. Junto con la Avenida del Ferrocarril MZA, esta v‚îú¬°a se convertir‚îú¬°a en una ronda de circunvalaci‚îú‚îÇn, con m‚îú√≠s de cinco kil‚îú‚îÇmetros de desarrollo. Para realizarla hab‚îú¬°a que superar la trinchera del Huerva mediante un nuevo puente. En la imagen, el Puente de la V‚îú¬°a Transversal. Al fondo, el ensanche de la Gran V‚îú¬°a. Al fondo, la torre del Cuartel de Transmisiones del Ej‚îú¬Ærcito de Tierra, que en 1943 se convertir‚îú√≠ en el Colegio de La Salle Gran V‚îú¬°a. M‚îú√≠s tarde, este puente recibir‚îú¬°a el nombre de "Emperador Augusto" (popularmente "de los Gitanos"), y la ronda de circunvalaci‚îú‚îÇn se quedar‚îú¬°a en calle de Juan Pablo Bonet.', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.64077500, -0.88974700, '0101000020E610000001DA56B3CE78ECBF158C4AEA04D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15137486006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15137486006.webp', 'https://www.flickr.com/photos/zaragozaantigua/15137486006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23953, 'Cine Gran V‚îú¬°a 1943', 'Esquina de la calle Padre Claret con el paseo de Calvo Sotelo (tramo luego redenominado Fernando el Cat‚îú‚îÇlico). Abajo a la derecha, el pretil del t‚îú‚ïënel ferroviario, que estaba a‚îú‚ïën sin cubrir. En el chafl‚îú√≠n, el cine Gran V‚îú¬°a reci‚îú¬Æn inaugurado ese mismo a‚îú‚ñío.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64410300, -0.89227700, '0101000020E6100000C022BF7E888DECBFB42094F771D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14761800597.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14761800597.webp', 'https://www.flickr.com/photos/zaragozaantigua/14761800597/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24033, 'Parque de Buenavista 1931', 'Imagen panor‚îú√≠mica, desde las alturas del cabezo de Buena Vista, del paseo central del hom‚îú‚îÇnimo parque, donde ten‚îú¬°a lugar una marcial promesa de fidelidad a la bandera por parte de una remesa de reclutas del cuerpo de instrucci‚îú‚îÇn. Al fondo, tras cruzar el puente del 14 de julio sobre el r‚îú¬°o Huerva, la mole del cuartel de artiller‚îú¬°a de Palafox. Como consecuencia derivada de la llegada de la Segunda Rep‚îú‚ïëblica en abril de ese a‚îú‚ñío, en el ‚îú√≠mbito castrense fueron reformados sus actos identitarios, entre los que destacaba la jura de bandera, que fue sustituida por la ceremonia de la promesa de fidelidad a la bandera, con una nueva f‚îú‚îÇrmula que modificaba antiguos conceptos, como dios, y rey: "Pregunta. ‚î¨‚îêPromet‚îú¬Æis ser fieles a la Naci‚îú‚îÇn, leales al Gobierno de la Rep‚îú‚ïëblica y obedecer y respetar y no abandonar al que os mande? Respuesta. S‚îú¬°, prometo. R‚îú¬Æplica. La Ley os amparar‚îú√≠ y la Naci‚îú‚îÇn os premiar‚îú√≠ si lo hac‚îú¬Æis, y si no, ser‚îú¬Æis castigados." Fuente visual: Foto Palacio, "La Hormiga de Oro".', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63440400, -0.89428200, '0101000020E6100000DCD8EC48F59DECBFCE39782634D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26355462601.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26355462601.webp', 'https://www.flickr.com/photos/zaragozaantigua/26355462601/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24077, 'P.‚î¨‚ïë de Fernando el Cat‚îú‚îÇlico 1943', 'Imagen capturada en el ensanche de Miralbueno y centrada en la moderna manzana de viviendas dise‚îú‚ñíada por los arquitectos Miguel ‚îú√ºngel Navarro P‚îú¬Ærez y Jos‚îú¬Æ Luis Navarro Anguela en el arranque de los n‚îú‚ïëmeros pares del tramo de la Gran V‚îú¬°a redenominado como paseo de Fernando el Cat‚îú‚îÇlico. En la achaflanada esquina destaca el nov‚îú¬°simo cinemat‚îú‚îÇgrafo Gran V‚îú¬°a, reci‚îú¬Æn inaugurado ese mismo a‚îú‚ñío. A ambos lados del paseo central sobresalen los soportes del tendido el‚îú¬Æctrico de la tranviaria l‚îú¬°nea 11 Parque. A izquierda y derecha, muretes que delimitaban la trinchera al aire del ferrocarril de los directos a Barcelona. Fuente visual: herederos Palomar-Palomar, AMZ.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64410300, -0.89227700, '0101000020E6100000C022BF7E888DECBFB42094F771D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38282945746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38282945746.webp', 'https://www.flickr.com/photos/zaragozaantigua/38282945746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22277, 'Troleb‚îú‚ïës 1966', '1966. El Troleb‚îú‚ïës 74 de la L‚îú¬°nea "Ciudad Jard‚îú¬°n" incorpor‚îú√≠ndose a San Juan Bosco desde la calle Pedro de Luna, para retornar a la Terminal de la Plaza de Santa Engracia. Esta unidad formaba parte de los 12 trolebuses de dos pisos adquiridos en 1961 a la compa‚îú‚ñí‚îú¬°a "London Transport". Esta L‚îú¬°nea, como todas las de troleb‚îú‚ïës, ser‚îú√≠ sustituida por autobuses en octubre de 1975, con la misma "justificaci‚îú‚îÇn" que para el caso de los tranv‚îú¬°as. A la izquierda, las parcelas de la Ciudad Jard‚îú¬°n. Al fondo, la mole del Edificio Torresol. A la derecha, el edificio de la Escuela de Magisterio. Los arbolitos est‚îú√≠n algo m‚îú√≠s crecidos.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.64451200, -0.90193000, '0101000020E61000003F00A94D9CDCECBF95F0845E7FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14974185081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14974185081.webp', 'https://www.flickr.com/photos/zaragozaantigua/14974185081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24093, 'CM Cardenal Xavierre 1943', 'Imagen capturada durante la provechosa visita a la ciudad del ministro de Educaci‚îú‚îÇn Nacional, el turolense Jos‚îú¬Æ Ib‚îú√≠‚îú‚ñíez Mart‚îú¬°n, a finales de junio de ese a‚îú‚ñío. Durante la tercera jornada de estancia en la ciudad, y tras recibir la Medalla de Caballero del Pilar, se dirigi‚îú‚îÇ a terrenos inmediatos a la Ciudad Universitaria para colocar la primera piedra del Colegio Mayor Cardenal Xavierre de los PP. Dominicos. En su emotivo discurso, record‚îú‚îÇ los "‚îú√≠ureos d‚îú¬°as del siglo XVI", y record‚îú‚îÇ a los dominicos "el ineludible deber de ayudar al r‚îú¬Ægimen en la ingente empresa de educar a una parte de la juventud universitaria y as‚îú¬° lograr fecundos resultados para el destino inmortal de la patria". Esto era as‚îú¬° porque "la nueva universidad, inspirada en el m‚îú√≠s profundo sentido cat‚îú‚îÇlico, ha de formar a los espa‚îú‚ñíoles selectos, a hombres completos que entiendan c‚îú‚îÇmo deben servir a su patria en la m‚îú√≠s noble ambici‚îú‚îÇn falangista de dar a Espa‚îú‚ñía una fuerte unidad interior, un indiscutible prestigio exterior y la garant‚îú¬°a de asegurar el pleno cumplimiento del destino de Espa‚îú‚ñía en el quehacer universal". En la imagen, el ministro acompa‚îú‚ñíado por locales jerarqu‚îú¬°as religiosas, entre las que destaca el arzobispo Rigoberto Dom‚îú¬Ænech Valls, y militares e institucionales como el rector de la Universidad, Miguel Sancho Izquierdo, que era a la vez decano de la Facultad de Derecho, y concejal del Ayuntamiento. Hacia el fondo, despejado fondo edilicio en torno al paseo de Fernando el Cat‚îú‚îÇlico.', 1943, 1943, 1943, 'Anos 40', 'UNIVERSIDAD', 41.64162500, -0.89552500, '0101000020E61000004703780B24A8ECBFE3A59BC420D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49367239193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49367239193.webp', 'https://www.flickr.com/photos/zaragozaantigua/49367239193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24170, 'Pasarela r‚îú¬°o Huerva 1965', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 1965. "Pasarela sobre el r‚îú¬°o Huerva". Cruzar el Huerva desde la Avenida de Goya se pod‚îú¬°a hacer mediante el tren, o por una pasarela peatonal que ascend‚îú¬°a desde Zumalac‚îú√≠rregui. Cuando las obras de cubrimiento de al trinchera del ferrocarril, esta pasarela era un observatorio muy privilegiado para supervisar los trabajos y contemplar los avances de cada d‚îú¬°a.. En la imagen, y a pesar de las expl‚îú¬°citas contraindicaciones, gente versada en obras p‚îú‚ïëblicas observando desde la pasarela c‚îú‚îÇmo crec‚îú¬°an los muros de la doble v‚îú¬°a en el nuevo puente sobre el Huerva (izquierda).', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64372600, -0.89024600, '0101000020E610000055A2EC2DE57CECBFDECA129D65D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14810459188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14810459188.webp', 'https://www.flickr.com/photos/zaragozaantigua/14810459188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
